def get_ludic(n):
    if n < 2:
        return []

    ludics = [1]
    i = 2
    while ludics[-1] <= n:
        is_ludic = True
        for l in ludics:
            if (i + l - 1) % l == 0:
                is_ludic = False
                break
        if is_ludic:
            ludics.append(i)
        i += 1

    return ludics

def get_ludic(n):
    if n < 1:
        return []
    l = [1] * (n + 1)
    i = 2
    while i * i <= n:
        for j in range(i * i, n + 1, i):
            l[j] = 0
        i += 1
    return [x for x in range(1, n + 1) if l[x]]

def get_ludic(n):
    ludics = [True] * (n + 1)
    ludics[0] = ludics[1] = False
    i = 2
    while i * i <= n:
        if ludics[i]:
            for j in range(i * i, n + 1, i):
                ludics[j] = False
        i += 1
    return [i for i in range(n + 1) if ludics[i]]

def get_ludic(n):
