def bell_Number(n):
    dp = [[0 for _ in range(n + 1)] for _ in range(n + 1)]

    for i in range(n + 1):
        dp[i][0] = 1

    for i in range(1, n + 1):
        for j in range(1, i + 1):
            dp[i][j] = dp[i - 1][j - 1] + dp[i][j - 1]

    return dp[n][n]

def bell_Number(n):
    bell = [[0 for _ in range(n + 1)] for _ in range(n + 1)]
    bell[0][0] = 1

    for i in range(1, n + 1):
        for j in range(i + 1):
            if j == 0:
                bell[i][j] = bell[i - 1][i]
            else:
                bell[i][j] = bell[i - 1][j - 1] + bell[i][j - 1]

    return bell[n][0]

def bell_Number(n):
