def get_median(list1, list2, n):
    if n == 1:
        return (list1[0] + list2[0]) / 2.0
    elif n == 2:
        return (max(list1[0], list2[0]) + min(list1[1], list2[1])) / 2.0

    mid = int(n / 2)
    if list1[mid] > list2[mid - 1]:
        return get_median(list1[mid:], list2[:mid], n - mid)
    else:
        return get_median(list1[:mid], list2[mid:], n - mid)

def get_median(nums1, nums2, n):
    i = j = k = 0
    mid = (n + 1) // 2
    med1, med2 = 0, 0

    while i < n and j < n:
        if nums1[i] <= nums2[j]:
            med1, med2 = med2, nums1[i]
            i += 1
        else:
            med1, med2 = med2, nums2[j]
            j += 1

        if (i + j) == mid:
            break

    if i == n:
        med1 = med2
        med2 = nums2[j + mid - (i + j)]
    elif j == n:
        med1 = med2
        med2 = nums1[i + mid - (i + j)]

    return (med1 + med2) / 2

