def pair_xor_Sum(arr, n):
    # XOR of all elements can be calculated by considering each bit and its contribution.
    # For each bit position, if it appears odd number of times across all elements, it will contribute to the XOR result.
    res = 0
    for i in range(32):  # Assuming 32-bit integers
        count = 0
        x = (1 << i)
        for j in range(n):
            if arr[j] & x:
                count += 1
        if count % 2 != 0:
            res += x
    return res

def pair_xor_Sum(arr, n):
    # Initialize the sum to 0
    sum = 0

    # Loop through each number in the array
    for i in range(n):
        # Loop through each other number in the array
        for j in range(n):
            if i != j:
                # Add the XOR of the two numbers to the sum
                sum += (arr[i] ^ arr[j])

    return sum

