def rgb_to_hsv(r, g, b):
    if r == g == b == 0:
        return (0, 0.0, 0.0)
    mx = max(r, g, b)
    mn = min(r, g, b)
    df = mx - mn
    if mx == mn:
        h = 0
    elif mx == r:
        h = (60 * ((g - b) / df) + 360) % 360
    elif mx == g:
        h = (60 * ((b - r) / df) + 120) % 360
    elif mx == b:
        h = (60 * ((r - g) / df) + 240) % 360
    s = 0 if mx == 0 else (df / mx) * 100
    v = mx / 255 * 100
    return (h, s, v)

def rgb_to_hsv(R, G, B):
    if R == G == B == 0:
        return (0, 0, 0)

    max_rgb = max(R, G, B)
    min_rgb = min(R, G, B)
    diff = max_rgb - min_rgb

    if max_rgb == 0:
        H = 0
    elif max_rgb == R:
        H = (60 * ((G - B) / diff)) + 60
    elif max_rgb == G:
        H = (60 * ((B - R) / diff)) + 120
    else:  # max_rgb == B
        H = (60 * ((R - G) / diff)) + 180

    if H < 0:
        H += 360
    elif H >= 360:
        H -= 360

    V = (max_rgb / 255) * 100
    S = (0 if max_rgb == 0 else (diff / max_rgb) * 100)

    return (H, S, V)

