    odd_product = 1
    has_even = False
    has_odd = False

    for num in nums:
        if num % 2 == 0:
            even_product *= num
            has_even = True
        else:
            odd_product *= num
            has_odd = True

        if has_even and has_odd:
            break

    return even_product * odd_product if has_even and has_odd else 0

