def odd_length_sum(arr):
    n = len(arr)
    total_sum = 0

    for i in range(n):
        # Calculate the contribution of arr[i] to the sum
        count = n - i
        if count % 2 == 1:
            total_sum += count * arr[i]

        # Calculate the contribution of elements before arr[i]
        prefix_sum = 0
        for j in range(i):
            prefix_sum += arr[j]
            if (i - j) % 2 == 1:
                total_sum += prefix_sum

        # Calculate the contribution of elements after arr[i]
        suffix_sum = 0
        for j in range(i + 1, n):
            suffix_sum += arr[j]
            if (j - i) % 2 == 1:
                total_sum += suffix_sum

    return total_sum

