def rgb_to_hsv(R, G, B):
    R /= 255.0
    G /= 255.0
    B /= 255.0

    mx = max(R, G, B)
    mn = min(R, G, B)

    if mx == mn:
        H = 0
    elif mx == R:
        H = (60 * ((G - B) / (mx - mn))) % 360
    elif mx == G:
        H = (60 * ((B - R) / (mx - mn))) + 120
    else:
        H = (60 * ((R - G) / (mx - mn))) + 240

    C = mx - mn
    V = mx
    S = 0 if mx == 0 else C / mx

    return (H, S, V)

def rgb_to_hsv(r, g, b):
    maxc = max(r, g, b)
    minc = min(r, g, b)
    delta = maxc - minc

    if delta == 0:
        h = 0
    elif maxc == r:
        h = (60 * ((g - b) / delta)) % 360
    elif maxc == g:
        h = (60 * ((b - r) / delta)) + 120
    else:
        h = (60 * ((r - g) / delta)) + 240

    if maxc == 0:
        s = 0
    else:
        s = (delta / maxc) * 100

    v = maxc * 100

    return (h, s, v)

