def max_run_uppercase(s):
    if not s:
        return 0

    max_length = 0
    current_length = 0
    prev_char = s[0]

    for char in s:
        if char.isupper():
            current_length += 1
            if prev_char.islower() or prev_char.isdigit():
                max_length = max(max_length, current_length)
            prev_char = char
        else:
            prev_char = char

    return max(max_length, current_length)

def max_run_uppercase(str):
    res = 0
    temp = 0
    for i in range(1, len(str)):
        if str[i - 1] != str[i]:
            res = max(res, temp)
            temp = 1
        else:
            temp += 1
    return max(res, temp)

